final:
module RefModule(
    input               clk,
    input               rst,
    input               data_in,

    output reg [8-1:1-1]    data_out
);

always@(posedge clk) begin
    if (rst)
        data_out <= 8'b00000000;
    else
        data_out <= {data_in, data_out[7:1]};
end

endmodule
